var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"아직까지 잠들지 않은 건가.","JPN":"まだ眠っていなかったのか。","ENG":"You're still awake.","TWN":"還沒有睡著嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"날이 늦었네. 계승식이 얼마 남지 않아 조급한 건 이해하나 쉴 때는 쉬어야지.","JPN":"もう遅い。継承式が間近で焦っているのはわかるが、休む時はきちんと休みなさい。","ENG":"It's late. I understand you're anxious with the succession ceremony approaching, but you need to rest too.","TWN":"天色已晚。雖然理解你對即將到來的繼承儀式感到焦慮，但該休息的時候還是要休息。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"시시각각 죽어가는 동료들의 목소리가 아직 귓가에 선명합니다.","JPN":"刻一刻と、死んでいく仲間たちの声がまだ耳に残っています。","ENG":"The voices of fallen comrades still echo in my ears.","TWN":"時時刻刻，耳邊仍清晰地迴響著同伴們逐漸逝去的聲音。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제 시간을 말미암아 한 명이라도 더 구할 수 있다면… 그리 하는 것이 귀족으로서의 의무겠지요.","JPN":"私の時間を使い、一人でも多く救うことができるのなら……そうするのが貴族としての義務でしょう。","ENG":"If staying awake a little longer could help save even one more life... then it's a duty I must bear as a noble.","TWN":"如果能在我的時間裡多救一個人……那就是作為貴族的義務吧。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"……그래.","JPN":"……ああ。","ENG":"...I see.","TWN":"……是啊。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"당신이 그렇다면 말릴 수는 없지.","JPN":"君がそうしたいのなら止めることなどできない。","ENG":"If that's how you feel, I won't stop you.","TWN":"如果你堅持的話，我也無法阻止你。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"먼저 잠드셔도 돼요, 알렌.","JPN":"先にお休みください、アレン。","ENG":"You're free to rest first, Allen.","TWN":"你可以先睡，艾倫。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"당신이 백작령에 힘을 쓴 탓에 요즘 통 볼 시간이 없지 않았나.","JPN":"君が伯爵領の仕事に励むあまり、最近は顔を合わせる時間もなかったじゃないか。","ENG":"You've been too busy managing the County to spend time together.","TWN":"你最近都在伯爵領地忙，我都沒什麼見到你。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"제국의 참모에게 조언을 구할 기회는 흔치 않으니, 잠깐은 괜찮겠지.","JPN":"帝国の参謀から助言してもらう機会は貴重だ。少しぐらいいいだろう。","ENG":"It's not often I get the advice of the Empire's top strategist, so I'll keep you a while longer.","TWN":"向帝國的參謀尋求建議的機會不常有，晚點睡沒問題。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그레이스. 자네도 알겠지만 북동쪽 페네리테 방어선이 침공당했네.","JPN":"グレース。君も知っているだろうが、北東のフェネリテ防御線が攻撃された。","ENG":"Grace. As you know, the northeastern Penelite defense line was breached.","TWN":"葛瑞絲。你也知道，東北方向的佩內裡特防線遭到了入侵。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"전황은 점점 불리해지고 있어. 전하께서도 결단이 필요하다고 생각하시는 것 같더군.","JPN":"戦況は徐々に不利になっている。殿下も決断が必要だとお考えになっているようだ。","ENG":"The tide of battle is turning against us. His Majesty believes decisive action is needed.","TWN":"戰況越來越不利了。看來殿下也認為需要做出決斷了。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"역시, 무구를 만드는 동안이라도 구원기사단과 함께 움직이는 편이 좋지 않겠나?","JPN":"武具を作っている間だけでも救世騎士団と行動を共にしてはどうだろうか？","ENG":"Shouldn't we coordinate with the Knights of Redemption, even while the Armament is still being forged?","TWN":"果然，在製作武具期間，還是和救贖騎士團一起行動比較好吧？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"각각의 방어선을 지키는 것조차 버거운 상황에 어찌 전력을 합치겠습니까?","JPN":"各々の防御線を守ることすら手に負えない状況下で、どうして戦力を一つにまとめるのですか。","ENG":"When each front is barely holding, how could we consolidate our forces?","TWN":"我們連各自的防線都難以守住，怎麼能合力呢？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"저는 대의를 위해서라는 이유로 신민들의 희생을 강요하고 싶지 않습니다.","JPN":"私は大義のためという理由で、臣民に犠牲を強要したくはないのです。","ENG":"I won't demand sacrifices from the people in the name of the greater good.","TWN":"我不想以大義為由強迫臣民犧牲。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그것이 별의 인도라면 따르겠네.","JPN":"それが星の導きなら従おう。","ENG":"If it's the guidance of the stars, I'll follow it.","TWN":"如果那是星之引導，我會跟隨。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"하지만 제국이 구원자를 찾은 시점에서 백작가의 전승이 큰 의미가 있을지는 의문이군.","JPN":"だが、帝国が救世主を見出した時点で伯爵家の伝承が果たして意味があるのかは疑問だ。","ENG":"Still, now that the Empire has found its Savior, I wonder if the legend of the Count's house holds any weight.","TWN":"但是在帝國找到了救贖主的情況下，伯爵家的傳承是否還有重要意義，令人懷疑。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"솔직한 심정으로 별의 무구가 전황에 큰 변화를 가져올 것 같지는 않아.","JPN":"正直、星の武具が戦況を大きく変えられるとは思えない。","ENG":"To be frank, I doubt the Star Armament alone can shift the course of this war.","TWN":"說實話，我覺得星之武具不會對戰況帶來太大的變化。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"구원자의 흑색제복에는 여러 의미가 있지만, 그것은 또한 공허한 밤하늘을 의미합니다.","JPN":"救世主の黒い礼装には色々な意味がありますが、それはまた虚ろな夜空を意味します。","ENG":"The black uniform of the Savior carries many meanings, but above all, it symbolizes the empty night sky.","TWN":"救贖者的黑色制服有著多重的意義，它也象徵著空虛的夜空。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"모든 것을 품을 수 있음에도 제 혼자서는 빛을 낼 수 없어 별빛을 필요로 하지요.","JPN":"すべてを抱くことができるにも関わらず、自分だけでは光を発することができないので、星の光を必要とするのです。","ENG":"It can embrace all things, yet cannot shine on its own. It needs starlight.","TWN":"雖然能夠包容一切，但自身無法發光，所以需要星光。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"레이의 힘만으로는 마왕을 쓰러트릴 수 없다는 건가?","JPN":"レイの力だけでは魔王を倒せないということか？","ENG":"So you're saying Ray can't defeat the Demon Lord alone?","TWN":"僅憑雷伊的力量無法擊敗魔王嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"전승에 따르면 열두 별빛이 모인 순간 인도자의 조율 아래 흑색제복은 본래의 모습을 되찾는다고 합니다.","JPN":"伝承によれば、12の星の光が集まった瞬間、導き手の調律のもとに黒い礼装は本来の姿を取り戻すそうです。","ENG":"According to legend, when the twelve starlights converge under the Guide's harmony, the black uniform regains its true form.","TWN":"傳說中，當十二顆星光彙聚之時，在引導者的調和下，黑色制服將恢復原本的樣貌。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"형태 없는 별빛이 어떤 모습을 갖출지는 온전히 구원자의 몫에 달렸으나…….","JPN":"形のない星の光がどんな姿になるのかは、救世主にかかっていますが……","ENG":"What shape that formless starlight takes depends on the Savior alone...","TWN":"無形的星光將呈現何種形態，完全取決於救贖者……"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"선대가 남긴 전승이 틀리지 않았다면, 그것이 제국에 가라앉은 어둠을 몰아낼 별빛임은 틀림없겠지요.","JPN":"先代が残した伝承が間違っていないなら、それが帝国に淀む闇を追い払う星の光に違いありません。","ENG":"But if the legend passed down is true, then that starlight will surely be what drives out the darkness plaguing the Empire.","TWN":"如果祖先留下的傳承沒有錯，那必定是驅散帝國沉寂黑暗的星光。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"무구개방… 확실히, 그 힘이라면 레이의 실력을 뒷받침해줄 수 있겠지.","JPN":"武具開放……確かにその力なら、レイの実力を後押ししてくれるだろう。","ENG":"Unleashing the Armament... If that power supports Ray, it could be a game-changer.","TWN":"武具解放……確實，那股力量可以支持雷伊的實力。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"하지만 자네 말대로 무구가 어떤 형태로 개방될지는 순전히 사용자의 몫에 달렸어.","JPN":"だが君の言うとおり、武具がどんな形で開放されるかは使用者次第だ。","ENG":"But as you said, its final form depends entirely on the wielder.","TWN":"但是正如你所說，武具以何種形式解放完全取決於使用者。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그 녀석의 심성을 생각한다면… 마왕의 숨통을 끊을 형태가 아닐 수도 있지 않겠나?","JPN":"あいつの性格を考えると……魔王にとどめを刺すような形ではない可能性もあるのではないか？","ENG":"And knowing him... it might not be something that can kill the Demon Lord.","TWN":"考慮到那傢伙的性情……也許不會是能扼殺魔王的形態吧？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};